mapper.select:
SELECT t1.ID, t1.APPLICATION_NO, t1.APPLICATION_TITLE, t1.APPLICATION_TYPE_CODE, t1.APPLICATION_TYPE_NAME, t1.FIXED_SERVICE_CATEGORY_CODE, t1.FIXED_SERVICE_CATEGORY_NAME, t1.REMARK, t1.DEPT_ID, t1.DEPT_NAME, t1.STATUS, t1.APPROVAL_REMARK, t1.APPROVAL_BY, t1.APPROVAL_BY_NAME, t1.APPROVAL_TIME, t1.CREATE_BY, t1.CREATE_BY_NAME, t1.CREATE_TIME, t1.UPDATE_BY, t1.UPDATE_BY_NAME, t1.UPDATE_TIME, t3.PROC_INST_ID, CASE WHEN t3.INSTANCE_STATUS IS NULL THEN '0' ELSE t3.INSTANCE_STATUS END AS processStatus, CASE WHEN t2.DICT_LABEL IS NULL THEN '未发起' ELSE t2.DICT_LABEL END AS processStatusLabel FROM E_MATERIAL_APPLICATION t1 LEFT JOIN BPM_BUSINESS_INSTANCE t3 ON t3.BUSINESS_DATA_ID = t1.ID LEFT JOIN M_DICT_DATA t2 ON t2.DICT_VALUE = t3.INSTANCE_STATUS AND t2.DICT_TYPE = 'APPROVAL_STATUS'
AND t1.APPLICATION_NO LIKE #{applicationNoPattern}
AND t1.APPLICATION_TITLE LIKE #{applicationTitlePattern}
AND t1.APPLICATION_TYPE_CODE = #{applicationTypeCode}
AND t1.DEPT_ID = #{deptId}
AND t1.STATUS = #{status}
ORDER BY CREATE_TIME DESC

SELECT A.ID AS APPLICATION_ID, A.APPLICATION_NO, A.APPLICATION_TITLE, A.APPLICATION_TYPE_CODE, A.APPLICATION_TYPE_NAME, A.FIXED_SERVICE_CATEGORY_CODE, A.FIXED_SERVICE_CATEGORY_NAME, A.REMARK, A.DEPT_ID, A.DEPT_NAME, A.STATUS, A.APPROVAL_REMARK, A.APPROVAL_BY, A.APPROVAL_BY_NAME, A.APPROVAL_TIME, A.CREATE_BY, A.CREATE_BY_NAME, A.CREATE_TIME, A.UPDATE_BY, A.UPDATE_BY_NAME, A.UPDATE_TIME, AD.ID AS DETAIL_ID, AD.APPLICATION_ID AS DETAIL_APPLICATION_ID, AD.MATERIAL_CODE_ID AS DETAIL_MATERIAL_CODE_ID, AD.MATERIAL_CODE AS DETAIL_MATERIAL_CODE, AD.MATERIAL_NAME AS DETAIL_MATERIAL_NAME, AD.SPECIFICATION_MODEL AS DETAIL_SPECIFICATION_MODEL, AD.UNIT AS DETAIL_UNIT, AD.APPLICATION_QUANTITY AS DETAIL_APPLICATION_QUANTITY, AD.ESTIMATED_PRICE AS DETAIL_ESTIMATED_PRICE, AD.AMOUNT AS DETAIL_AMOUNT, AD.FLOW_DIRECTION AS DETAIL_FLOW_DIRECTION, AD.SUPPLY_TIME_LIMIT AS DETAIL_SUPPLY_TIME_LIMIT, AD.SUGGESTED_BRAND AS DETAIL_SUGGESTED_BRAND, AD.SPECIFICATION_DESC AS DETAIL_SPECIFICATION_DESC, AD.PURCHASE_DETAIL_ID AS DETAIL_PURCHASE_DETAIL_ID,
NVL(SUM(WID.REMAINING_QUANTITY), 0) AS DETAIL_STOCK_QUANTITY,
0 AS DETAIL_STOCK_QUANTITY,
AD.CREATE_BY AS DETAIL_CREATE_BY, AD.CREATE_BY_NAME AS DETAIL_CREATE_BY_NAME, AD.CREATE_TIME AS DETAIL_CREATE_TIME, AD.UPDATE_BY AS DETAIL_UPDATE_BY, AD.UPDATE_BY_NAME AS DETAIL_UPDATE_BY_NAME, AD.UPDATE_TIME AS DETAIL_UPDATE_TIME FROM E_MATERIAL_APPLICATION A LEFT JOIN E_MATERIAL_APPLICATION_DETAIL AD ON A.ID = AD.APPLICATION_ID
LEFT JOIN E_MATERIAL_WAREHOUSE_IN_DETAIL WID ON AD.MATERIAL_CODE_ID = WID.MATERIAL_ID LEFT JOIN E_MATERIAL_WAREHOUSE_IN WI ON WID.WAREHOUSE_IN_ID = WI.ID AND WI.WAREHOUSE_ID = #{warehouseId}
AND A.APPLICATION_NO LIKE #{applicationNoPattern}
AND A.APPLICATION_TITLE LIKE #{applicationTitlePattern}
AND A.APPLICATION_TYPE_CODE = #{applicationTypeCode}
AND A.DEPT_ID = #{deptId}
AND A.CREATE_BY = #{createBy}
AND A.STATUS = #{status}
AND WI.WAREHOUSE_ID = #{warehouseId} AND WI.ACCEPTANCE_STATUS = 1
GROUP BY A.ID, A.APPLICATION_NO, A.APPLICATION_TITLE, A.APPLICATION_TYPE_CODE, A.APPLICATION_TYPE_NAME, A.FIXED_SERVICE_CATEGORY_CODE, A.FIXED_SERVICE_CATEGORY_NAME, A.REMARK, A.DEPT_ID, A.DEPT_NAME, A.STATUS, A.APPROVAL_REMARK, A.APPROVAL_BY, A.APPROVAL_BY_NAME, A.APPROVAL_TIME, A.CREATE_BY, A.CREATE_BY_NAME, A.CREATE_TIME, A.UPDATE_BY, A.UPDATE_BY_NAME, A.UPDATE_TIME, AD.ID, AD.APPLICATION_ID, AD.MATERIAL_CODE_ID, AD.MATERIAL_CODE, AD.MATERIAL_NAME, AD.SPECIFICATION_MODEL, AD.UNIT, AD.APPLICATION_QUANTITY, AD.ESTIMATED_PRICE, AD.AMOUNT, AD.FLOW_DIRECTION, AD.SUPPLY_TIME_LIMIT, AD.SUGGESTED_BRAND, AD.SPECIFICATION_DESC, AD.PURCHASE_DETAIL_ID, AD.CREATE_BY, AD.CREATE_BY_NAME, AD.CREATE_TIME, AD.UPDATE_BY, AD.UPDATE_BY_NAME, AD.UPDATE_TIME
ORDER BY A.CREATE_TIME DESC, AD.CREATE_TIME ASC

SELECT COUNT(*)
FROM E_MATERIAL_APPLICATION
WHERE APPLICATION_NO = #{applicationNo}

    AND ID != #{id}

mapper.update:
UPDATE E_MATERIAL_APPLICATION
STATUS = #{status,jdbcType=VARCHAR},
APPROVAL_REMARK = #{approvalRemark,jdbcType=VARCHAR},
APPROVAL_BY = #{loginUserId,jdbcType=NUMERIC}, APPROVAL_BY_NAME = #{loginUserName,jdbcType=VARCHAR}, APPROVAL_TIME = #{now,jdbcType=TIMESTAMP}
WHERE ID = #{id}
